import json
import random
import time
from datetime import datetime
from pathlib import Path

ts = int(datetime.utcnow().timestamp())
rand = random.randint(1000, 9999)
session_id = f'sess_{ts}_{rand}'

freeze_file = Path('/data/linkedin_intel/state/freeze.json')
frozen = False
freeze_reason = ''

if freeze_file.exists():
    try:
        state = json.loads(freeze_file.read_text())
        if state.get('frozen', False):
            resume_str = state.get('resumeAfter', '')
            if resume_str:
                resume_dt = datetime.fromisoformat(resume_str)
                now_dt = datetime.utcnow()
                if now_dt < resume_dt:
                    frozen = True
                    freeze_reason = state.get('reason', 'UNKNOWN')
                else:
                    freeze_file.write_text(
                        json.dumps({
                            'frozen': False,
                            'unfrozenAt': now_dt.isoformat()
                        })
                    )
    except Exception as ex:
        freeze_reason = f'FREEZE_READ_ERROR: {str(ex)}'

day_of_year = datetime.utcnow().timetuple().tm_yday
is_blackout = (day_of_year % 14 == 0)

jitter_seconds = random.randint(0, 480)
time.sleep(jitter_seconds)

return [
    {
        'json': {
            'sessionId': session_id,
            'frozen': frozen,
            'freezeReason': freeze_reason,
            'isBlackout': is_blackout,
            'startedAt': datetime.utcnow().isoformat(),
            'jitterSeconds': jitter_seconds
        }
    }
]

import json
import time
import requests
from stem import Signal
from stem.control import Controller
from pathlib import Path

session_id = _items[0]['json']['sessionId']

TOR_PASSWORD = 'R3XeN3jmWiFINaRX'
TOR_CONTROL_PORT = 9051
ALLOWED_COUNTRIES = {'US', 'GB', 'DE', 'CA', 'AU'}
BLOCKED_ORGS = ['Amazon', 'Google', 'Microsoft', 'DigitalOcean', 'Cloudflare', 'Linode']

TOR_PROXIES = {
    'http': 'socks5h://127.0.0.1:9050',
    'https': 'socks5h://127.0.0.1:9050'
}

def rotate_circuit():
    try:
        with Controller.from_port(port=TOR_CONTROL_PORT) as ctrl:
            ctrl.authenticate(password=TOR_PASSWORD)
            ctrl.signal(Signal.NEWNYM)
        time.sleep(5)
        return True
    except Exception:
        return False

def get_ip_info():
    try:
        r = requests.get(
            'https://ipinfo.io/json',
            proxies=TOR_PROXIES,
            timeout=15
        )
        return r.json()
    except Exception:
        return {}

def is_usable(info):
    country = info.get('country', '')
    org = info.get('org', '')
    if country not in ALLOWED_COUNTRIES:
        return False, f'Country not allowed: {country}'
    if any(b in org for b in BLOCKED_ORGS):
        return False, f'Datacenter org: {org}'
    return True, 'OK'

ip_result = {
    'success': False,
    'ip': None,
    'country': None,
    'timezone': 'America/New_York',
    'attempts': 0
}

for attempt in range(1, 4):
    ip_result['attempts'] = attempt
    if not rotate_circuit():
        continue
    info = get_ip_info()
    if not info:
        continue
    usable, reason = is_usable(info)
    if usable:
        ip_result['success'] = True
        ip_result['ip'] = info.get('ip', 'unknown')
        ip_result['country'] = info.get('country', 'unknown')
        ip_result['timezone'] = info.get('timezone', 'America/New_York')
        break

log_file = Path('/data/linkedin_intel/logs/sessions.log')
log_file.parent.mkdir(parents=True, exist_ok=True)
with open(log_file, 'a') as f:
    f.write(json.dumps({
        'event': 'IP_ROTATION',
        'sessionId': session_id,
        'result': ip_result
    }) + '\n')

return [
    {
        'json': {
            'sessionId': session_id,
            'startedAt': _items[0]['json'].get('startedAt', ''),
            'ipRotated': ip_result['success'],
            'currentIp': ip_result['ip'],
            'ipCountry': ip_result['country'],
            'sessionTimezone': ip_result['timezone'],
            'rotationAttempts': ip_result['attempts']
        }
    }
]
